scwin.f_Retrieve = async function () {
  let commonChecked = commonChe.getValue() != "";
  if (commonChecked == false) {
    if (bilgMchtCd.getValue() == "") {
      await $c.gus.cfAlertMsg($p, MSG_CM_ERR_002, ["화주코드"]);
      bilgMchtCd.setFocus();
      return;
    }
    if (bilgMcht.getValue() == "") {
      await $c.gus.cfAlertMsg($p, MSG_CM_ERR_002, ["화주명"]);
      bilgMcht.setFocus();
      return;
    }
  }
  if (ctrtNo.getValue() == "") {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_002, ["계약서"]);
    bilgMchtCd.setFocus();
    return;
  }
  dma_retrieve.set("branCd", co_lc_logisticsBranch.getValue());
  dma_retrieve.set("ctrtNo", ctrtNo.getValue());
  dma_retrieve.set("copCo", copCoCd.getValue());
  dma_retrieve.set("dptDistrictCd", dptDistrictCd.getValue().trim());
  dma_retrieve.set("arvDistrictCd", arvDistrictCd.getValue().trim());
  dma_retrieve.set("commCd", commCd.getValue());
  dma_retrieve.set("adptDt", wrkStDt.getValue().trim() == "" ? scwin.strDate : wrkStDt.getValue().trim());
  dma_retrieve.set("eqKndCd", lo_eqKndCd.getValue());
  dma_retrieve.set("pchsAmt", lo_pchsAmt.getValue());
  await $c.sbm.execute($p, sbm_retrieve);
};
scwin.f_Save = async function () {
  if (!ds_empSave.isUpdated()) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_001, ["자료"]);
    return;
  }
  let chkValid = await $c.gus.cfValidate($p, [gr_emp]);
  if (!chkValid) {
    return;
  }
  let chk = await $c.gus.cfConfirmMsg($p, MSG_CM_CRM_001);
  if (chk == true) {
    scwin.insertYN = "0";
    dma_retrieve.set("branCd", co_lc_logisticsBranch.getValue());
    dma_retrieve.set("ctrtNo", ctrtNo.getValue());
    dma_retrieve.set("copCo", copCoCd.getValue());
    dma_retrieve.set("dptDistrictCd", dptDistrictCd.getValue().trim());
    dma_retrieve.set("arvDistrictCd", arvDistrictCd.getValue().trim());
    dma_retrieve.set("commCd", commCd.getValue());
    dma_retrieve.set("adptDt", wrkStDt.getValue().trim());
    dma_retrieve.set("eqKndCd", lo_eqKndCd.getValue());
    dma_retrieve.set("pchsAmt", lo_pchsAmt.getValue());
    for (let i = 0; i < ds_empSave.getRowCount(); i++) {
      if (ds_empSave.getCellData(i, "copCoClntNm").trim() == "" || ds_empSave.getCellData(i, "copCoClntNm") == null) {
        ds_empSave.setCellData(i, "copCoClntNo", "999999");
      }
    }
    for (let i = 0; i < ds_empCross2.getRowCount(); i++) {
      if (ds_empCross2.getCellData(i, "wrkStHh").length != 4) {
        await $c.win.alert($p, "적용시간(From)을 확인해 주세요");
        ds_empCross2.setRowPosition(i);
        gr_emp.setFocusedCell(i, "wrkStHh");
        return;
      } else if (ds_empCross2.getCellData(i, "wrkEndHh").length != 4) {
        await $c.win.alert($p, "적용시간(To)을 확인해 주세요");
        ds_empCross2.setRowPosition(i);
        gr_emp.setFocusedCell(i, "wrkEndHh");
        return;
      }
    }
    await $c.sbm.execute($p, sbm_saveEmp);
  }
};
scwin.f_Copy = async function () {
  let cnt = ds_empSave.getRowCount();
  if (ds_empSave.getCellData(0, "ctrtNo") == ctrtNo.getValue() && ds_empSave.getCellData(0, "trfClsCd") == lo_pchsAmt.getValue()) {
    await $c.gus.cfAlertMsg($p, "같은 계약서의 같은요율은 복사할 수 없습니다.");
    return;
  }
  for (let i = 0; i < cnt; i++) {
    ds_empSave.setCellData(i, "ctrtNo", ctrtNo.getValue());
    ds_empSave.setCellData(i, "trfClsCd", lo_pchsAmt.getValue());
  }
  if (!ds_empSave.isUpdated()) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_001, ["자료"]);
    return;
  }
  let chkValid = await $c.gus.cfValidate($p, [gr_emp]);
  if (!chkValid) {
    return;
  }
  let chk = await $c.gus.cfConfirmMsg($p, MSG_CM_CRM_001);
  if (chk == true) {
    scwin.insertYN = "0";
    dma_retrieve.set("branCd", co_lc_logisticsBranch.getValue());
    dma_retrieve.set("ctrtNo", ctrtNo.getValue());
    dma_retrieve.set("copCo", copCoCd.getValue());
    dma_retrieve.set("dptDistrictCd", dptDistrictCd.getValue().trim());
    dma_retrieve.set("arvDistrictCd", arvDistrictCd.getValue().trim());
    dma_retrieve.set("commCd", commCd.getValue());
    dma_retrieve.set("adptDt", wrkStDt.getValue().trim());
    dma_retrieve.set("eqKndCd", lo_eqKndCd.getValue());
    dma_retrieve.set("pchsAmt", lo_pchsAmt.getValue());
    await $c.sbm.execute($p, sbm_saveEmp2);
  }
};
scwin.f_Delete = function () {
  let rowState = 0;
  let row = 0;
  let newRow = 0;
  let xkeycnt = 0;
  for (let i = ds_empCross2.getRowCount() - 1; i >= 0; i--) {
    rowState = ds_empCross2.getRowStatus(i);
    if (rowState == "U") {
      row = i;
      xkeycnt = Math.floor((ds_empCross2.getColumnCount() - 21) / 2);
      newRow = xkeycnt * (row + 1);
      ds_empCross2.removeRow(i);
      for (let j = newRow - 1; j >= newRow - xkeycnt; j--) {
        if (j >= 0 && j < ds_empSave.getRowCount()) {
          ds_empSave.removeRow(j);
        }
      }
    }
  }
  $c.gus.cfDisableKey($p);
  $c.gus.cfDisableBtn($p, ["btn_Upt"]);
  scwin.insertYN = "0";
};
