scwin.isUpdate = function (val) {
  let j = 0;
  let chkTF = false;
  for (let i = 0; i < ds_empCross2.getRowCount(); i++) {
    if (ds_empCross2.isUpdated()) {
      j++;
      if (ds_empCross2.getCellData(i, val) != "") {
        chkTF = scwin.dateFormat(ds_empCross2.getCellData(i, val), i);
        if (!chkTF) {
          return chkTF;
        }
      }
    }
  }
  return true;
};
scwin.dateFormat = async function (ymd, i) {
  let d = ymd;
  let inputYear = d.substr(0, 4);
  let inputMonth = d.substr(4, 2) - 1;
  let inputDate = d.substr(6, 2);
  let resultDate = new Date(inputYear, inputMonth, inputDate);
  if (resultDate.getFullYear() != inputYear || resultDate.getMonth() != inputMonth || resultDate.getDate() != inputDate) {
    await $c.win.alert($p, "날짜 입력이 잘못되었습니다.");
    ds_empCross2.setRowPosition(i);
    gr_emp.setFocusedCell(i, "adptDt");
    return false;
  } else {
    return true;
  }
};
